def _dremio_source_to_nested(dremio_source: DremioSource) -> DremioSourceNested:
    """Convert flat DremioSource to nested format."""
    attrs = DremioSourceAttributes()
    _populate_dremio_source_attrs(attrs, dremio_source)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        dremio_source, _DREMIO_SOURCE_REL_FIELDS, DremioSourceRelationshipAttributes
    )
    return DremioSourceNested(
        guid=dremio_source.guid,
        type_name=dremio_source.type_name,
        status=dremio_source.status,
        version=dremio_source.version,
        create_time=dremio_source.create_time,
        update_time=dremio_source.update_time,
        created_by=dremio_source.created_by,
        updated_by=dremio_source.updated_by,
        classifications=dremio_source.classifications,
        classification_names=dremio_source.classification_names,
        meanings=dremio_source.meanings,
        labels=dremio_source.labels,
        business_attributes=dremio_source.business_attributes,
        custom_attributes=dremio_source.custom_attributes,
        pending_tasks=dremio_source.pending_tasks,
        proxy=dremio_source.proxy,
        is_incomplete=dremio_source.is_incomplete,
        provenance_type=dremio_source.provenance_type,
        home_id=dremio_source.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _dremio_source_from_nested(nested: DremioSourceNested) -> DremioSource:
    """Convert nested format to flat DremioSource."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else DremioSourceAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _DREMIO_SOURCE_REL_FIELDS,
        DremioSourceRelationshipAttributes,
    )
    return DremioSource(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_dremio_source_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _dremio_source_to_nested_bytes(dremio_source: DremioSource, serde: Serde) -> bytes:
    """Convert flat DremioSource to nested JSON bytes."""
    return serde.encode(_dremio_source_to_nested(dremio_source))


def _dremio_source_from_nested_bytes(data: bytes, serde: Serde) -> DremioSource:
    """Convert nested JSON bytes to flat DremioSource."""
    nested = serde.decode(data, DremioSourceNested)
    return _dremio_source_from_nested(nested)


